class Solution:
    def distinctSequences(self, n: int) -> int:
        MOD = 10**9 + 7
        @lru_cache(None)
        def dp(i, prev):
            if i == n:
                return 1
            res = 0
            for x in range(1, 7):
                if x != prev and (i == 1 or gcd(x, prev) == 1):
                    res += dp(i + 1, x)
                    res %= MOD
            return res
        return sum(dp(1, x) for x in range(1, 7)) % MOD

